<?php
declare(strict_types=1);require dirname(__DIR__).'/bootstrap.php';$admin=vp3_require_admin_permission('sales.manage');if(vp3_method()==='POST'){vp3_verify_csrf();$id=(int)vp3_input('id');$status=vp3_input('status');if(in_array($status,['requested','scheduled','completed','cancelled','no_show'],true))vp3_db()->prepare('UPDATE demo_requests SET status=?,scheduled_at=NULLIF(?,\'\'),meeting_url=NULLIF(?,\'\'),internal_notes=?,updated_at=NOW() WHERE id=?')->execute([$status,vp3_input('scheduled_at'),vp3_input('meeting_url'),vp3_input('internal_notes'),$id]);vp3_redirect('admin/demo-requests.php');}$rows=[];try{$rows=vp3_db()->query('SELECT d.*,l.name,l.email,l.company_name,l.project_name,l.project_type FROM demo_requests d JOIN leads l ON l.id=d.lead_id ORDER BY FIELD(d.status,\'requested\',\'scheduled\',\'completed\',\'no_show\',\'cancelled\'),d.preferred_date,d.created_at DESC')->fetchAll();}catch(Throwable){}$pageTitle='Demo Requests';require VP3_ROOT.'/includes/admin-header.php';?>
<div class="admin-page-head"><div><span class="admin-kicker">Discovery calendar</span><h1>Demo requests</h1><p>Schedule and record the outcome of creative discovery calls.</p></div></div><div class="demo-request-grid"><?php foreach($rows as $d):?><article class="card"><div class="project-card-top"><span class="badge <?=vp3_e($d['status'])?>"><?=vp3_e($d['status'])?></span><a href="lead.php?id=<?=(int)$d['lead_id']?>">Open lead</a></div><h2><?=vp3_e($d['name'])?></h2><p><?=vp3_e($d['project_name']?:$d['company_name']?:$d['project_type'])?></p><dl class="detail-list"><dt>Preferred</dt><dd><?=vp3_e(($d['preferred_date']?:'Flexible').' · '.($d['preferred_time_window']?:'Any time'))?></dd><dt>Timezone</dt><dd><?=vp3_e($d['timezone'])?></dd><dt>Format</dt><dd><?=vp3_e($d['meeting_format'])?></dd><dt>Goals</dt><dd><?=vp3_e($d['goals'])?></dd></dl><form method="post"><?=vp3_csrf_field()?><input type="hidden" name="id" value="<?=(int)$d['id']?>"><div class="field"><label>Status</label><select name="status"><?php foreach(['requested','scheduled','completed','cancelled','no_show'] as $v):?><option <?=$d['status']===$v?'selected':''?>><?=$v?></option><?php endforeach;?></select></div><div class="field"><label>Scheduled</label><input type="datetime-local" name="scheduled_at" value="<?=vp3_e($d['scheduled_at']?str_replace(' ','T',substr($d['scheduled_at'],0,16)):'')?>"></div><div class="field"><label>Meeting URL</label><input type="url" name="meeting_url" value="<?=vp3_e($d['meeting_url'])?>"></div><div class="field"><label>Internal notes</label><textarea name="internal_notes"><?=vp3_e($d['internal_notes'])?></textarea></div><button class="button small">Save</button></form></article><?php endforeach;?><?php if(!$rows):?><div class="empty-state"><p>No demo requests.</p></div><?php endif;?></div>
<?php require VP3_ROOT.'/includes/admin-footer.php';?>
